package com.treeeducation.ioas.lead;
import jakarta.persistence.*;import java.time.Instant;
/** Sales/operation lead generated from shared media assets. */
@Entity @Table(name="lead_record") public class Lead{ @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(nullable=false) private Long packageId; @Column(nullable=false) private Long assetFileId; private Long operatorId; @Column(nullable=false,length=120) private String customerName; @Column(length=40) private String phone; @Column(length=1000) private String remark; @Enumerated(EnumType.STRING) @Column(nullable=false,length=30) private LeadStatus status=LeadStatus.new_lead; @Column(nullable=false) private Long createdBy; @Column(nullable=false) private Instant createdAt=Instant.now(); private Instant updatedAt=Instant.now(); public Long getId(){return id;} public void setId(Long id){this.id=id;} public Long getPackageId(){return packageId;} public void setPackageId(Long packageId){this.packageId=packageId;} public Long getAssetFileId(){return assetFileId;} public void setAssetFileId(Long assetFileId){this.assetFileId=assetFileId;} public Long getOperatorId(){return operatorId;} public void setOperatorId(Long operatorId){this.operatorId=operatorId;} public String getCustomerName(){return customerName;} public void setCustomerName(String customerName){this.customerName=customerName;} public String getPhone(){return phone;} public void setPhone(String phone){this.phone=phone;} public String getRemark(){return remark;} public void setRemark(String remark){this.remark=remark;} public LeadStatus getStatus(){return status;} public void setStatus(LeadStatus status){this.status=status;} public Long getCreatedBy(){return createdBy;} public void setCreatedBy(Long createdBy){this.createdBy=createdBy;} public Instant getCreatedAt(){return createdAt;} public void setCreatedAt(Instant createdAt){this.createdAt=createdAt;} public Instant getUpdatedAt(){return updatedAt;} public void setUpdatedAt(Instant updatedAt){this.updatedAt=updatedAt;} }
